IDENTIFIER: str = "min_int"
HINT: str = "IML integers have arbitrary precision, so there is no built-in `max_int` or `min_int` derived from `Sys.int_size`. Consider refactoring to use a specific constant for your use case or making it opaque if it\u0027s externally defined."
RULE_ID: str = "unknown-id-ocaml-stdlib-sys_int_size"

# Matches both message shapes emitted by ImandraX:
#   Unknown identifier `foo`.
#   Unknown identifier "foo".
#   Unknown function `Mod.fn`.
_MSG_RE = re.compile(r'Unknown (?:identifier|function) [`"](?P<name>[^`"]+)[`"]')


