# Diagnostic
# ====================


class UnknownIdOCamlStdlibRule(BaseRule):
    id: ClassVar[str] = RULE_ID
    description: ClassVar[str] = (
        f"OCaml-stdlib identifier `{IDENTIFIER}` is not available in IML"
    )
    severity: ClassVar[Severity] = Severity.Error


UNKNOWN_ID_RULE = UnknownIdOCamlStdlibRule()


class UnknownIdOCamlStdlibDiag(BaseDiag):
    rule: ClassVar[UnknownIdOCamlStdlibRule] = UNKNOWN_ID_RULE  # pyright: ignore[reportIncompatibleVariableOverride]
    error_kind: ClassVar[ErrorKind] = ErrorKind.TYPE_ERR

    identifier: str

    @computed_field
    @property
    def message(self) -> str:
        return f"Unknown identifier `{self.identifier}`. {HINT}"


# %%
# Check
# ====================


def check_unknown_id_ocaml_stdlib(
    iml: str, eval_res: EvalRes
) -> UnknownIdOCamlStdlibDiag | None:
    """Match an `Unknown identifier`/`Unknown function` TypeErr for `min_int`.

    Conditions:
    - a TypeErr whose message matches `Unknown (identifier|function) "<name>"`
    - the parsed `<name>` equals `min_int`
    """
    _ = iml  # unused: the error message is sufficient.
    for err in eval_res.errors:
        if ErrorKind.from_proto_kind(err.kind) != ErrorKind.TYPE_ERR:
            continue
        if err.msg is None:
            continue
        m = _MSG_RE.search(err.msg.msg)
        if m is None:
            continue
        if m.group("name") != IDENTIFIER:
            continue
        locs = err.msg.locs
        loc: Loc | NoLoc
        if locs and locs[0].start is not None and locs[0].stop is not None:
            s, e = locs[0].start, locs[0].stop
            loc = Loc(
                start_byte=0,
                end_byte=0,
                start_point=(s.line - 1, s.col - 1),
                end_point=(e.line - 1, e.col - 1),
            )
        else:
            loc = NoLoc(reason="error message has no location")
        return UnknownIdOCamlStdlibDiag(loc=loc, identifier=IDENTIFIER)
    return None


